  mode: "isolated" | "live";
  property_id?: string;
}): Promise<SimIngestResponse> {
  const r = await fetch(`${base}/sim/ingest`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(body),
  });
  if (!r.ok) {
