def apply_patch_plan(plan: PatchPlan, *, wiki_dir: Path) -> PatchApplyResult:
    if _PROPERTY_ID_RE.fullmatch(plan.property_id) is None:
        raise ValueError(f"invalid property_id: {plan.property_id!r}")

    property_root = wiki_dir / plan.property_id
    property_root.mkdir(parents=True, exist_ok=True)

    touched: list[Path] = []
    unique_touched: list[Path] = []
    seen: set[Path] = set()
    for op in plan.ops:
        path = _apply_one(property_root, op)
        if path is None:
            continue
        touched.append(path)
        if path not in seen:
            seen.add(path)
            unique_touched.append(path)

    summary = plan.summary.strip() or plan.event_type
    rels = tuple(_relative_posix(p, property_root) for p in unique_touched)
    append_feedback(
        property_root,
        event_id=plan.event_id,
        event_type=plan.event_type,
        property_id=plan.property_id,
        summary=summary,
        applied_ops=len(touched),
        deferred_ops=0,
        touched=rels,
        op_shapes=_op_shapes(plan.ops),
    )
    commit_sha = commit_all(wiki_dir, message=f"ingest({plan.event_id}): {summary}".strip())
    return PatchApplyResult(
        event_id=plan.event_id,
        applied_ops=len(touched),
        commit_sha=commit_sha,
        touched=rels,
    )


def head_commit(wiki_dir: Path) -> str | None:
    return head_sha(wiki_dir)


def _apply_one(property_root: Path, op: PatchOp) -> Path | None:
    if isinstance(op, CreatePageOp):
        return _do_create_page(property_root, op)
    if isinstance(op, UpsertSectionOp):
        return _do_upsert_section(property_root, op)
    if isinstance(op, AppendSectionOp):
        return _do_append_section(property_root, op)
    if isinstance(op, PrependLogOp):
        return _do_prepend_log(property_root, op)
    raise PatchOperationError(f"unknown op: {op!r}")


def _do_create_page(property_root: Path, op: CreatePageOp) -> Path | None:
    file_path = property_file_path(property_root, op.path)
    _require_md(file_path)
    existing = file_path.read_text(encoding="utf-8") if file_path.is_file() else ""
    new_content = create_page(
        path_exists=file_path.is_file(),
        existing=existing,
        frontmatter=op.frontmatter,
        body=op.body,
    )
    if new_content == existing:
        return None
    atomic_write_text(file_path, new_content)
    return file_path


def _do_upsert_section(property_root: Path, op: UpsertSectionOp) -> Path | None:
    file_path = property_file_path(property_root, op.path)
    _require_md(file_path)
    existing = file_path.read_text(encoding="utf-8") if file_path.is_file() else ""
    base = existing or render_page(frontmatter=None, body="")
    new_content = upsert_section(base, heading=op.heading, body=op.body)
    if new_content == existing:
        return None
    atomic_write_text(file_path, new_content)
    return file_path


def _do_append_section(property_root: Path, op: AppendSectionOp) -> Path | None:
    file_path = property_file_path(property_root, op.path)
    _require_md(file_path)
    existing = file_path.read_text(encoding="utf-8") if file_path.is_file() else ""
    base = existing or render_page(frontmatter=None, body="")
    new_content = append_section(base, heading=op.heading, line=op.line)
    if new_content == existing:
        return None
    atomic_write_text(file_path, new_content)
    return file_path

    return property_root / FEEDBACK_FILENAME


def append_feedback(
    property_root: Path,
    *,
    event_id: str,
    event_type: str,
    property_id: str,
    summary: str,
    applied_ops: int,
    deferred_ops: int = 0,
    touched: Iterable[str] = (),
    op_shapes: Iterable[dict[str, str]] = (),
    kind: str = "ingest",
) -> bool:
    """Append one JSONL line to `_hermes_feedback.jsonl`.

    Idempotent on `event_id`: returns False without writing if a line with the
    same event_id is already present. Returns True when a new line is written.
    """
    path = feedback_path(property_root)
    if _has_event(path, event_id):
        log.info("hermes_feedback_skipped", event_id=event_id, reason="duplicate")
        return False

    record = {
        "kind": kind,
        "ts": datetime.now(UTC).isoformat(),
        "event_id": event_id,
        "event_type": event_type,
        "property_id": property_id,
        "summary": summary,
        "applied_ops": applied_ops,
        "deferred_ops": deferred_ops,
        "touched": list(touched),
        "op_shapes": [dict(s) for s in op_shapes],
    }
    line = json.dumps(record, ensure_ascii=False, separators=(",", ":")) + "\n"

    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("a", encoding="utf-8") as f:
        f.write(line)
    log.info(
        "hermes_feedback_appended",
        event_id=event_id,
        property_id=property_id,
        applied_ops=applied_ops,
    )
    return True


def iter_feedback(property_root: Path) -> Iterator[FeedbackRecord]:
    """Yield each `FeedbackRecord` from the substrate file. Empty if file is missing."""
    path = feedback_path(property_root)
    if not path.is_file():
        return
    with path.open("r", encoding="utf-8") as f:
        for raw in f:
            stripped = raw.strip()
            if not stripped:
                continue
            try:
                row = json.loads(stripped)
            except json.JSONDecodeError:
                log.warning("hermes_feedback_corrupt_line", line=stripped[:120])
                continue
            if not isinstance(row, dict):
                continue
            yield FeedbackRecord.from_dict(row)


def _coerce_int(value: object) -> int:
    if isinstance(value, bool):
        return int(value)
    if isinstance(value, int):
        return value
    if isinstance(value, str) and value.strip().lstrip("-").isdigit():
        return int(value)
    return 0


def _has_event(path: Path, event_id: str) -> bool:
    if not path.is_file():
        return False
    with path.open("r", encoding="utf-8") as f:
        for raw in f:
            stripped = raw.strip()
            if not stripped:
                continue
            try:
                row = json.loads(stripped)
            except json.JSONDecodeError:
                continue
            if isinstance(row, dict) and row.get("event_id") == event_id:
                return True
    return False

